1	const PROCESSING_FEE = 5;
2	const FIRST_CONTRACT_INSURANCE_RATE = 0.1;
3	const LOYALTY_DISCOUNT_RATE = 0.2;
4	const LOYALTY_THRESHOLD_YEARS = 2;
5	const FOLLOW_UP_CONTRACT_DISCOUNT_RATE = 0.15;
6	const COMPONENT_BASE_PREMIUM = 25;
7	const COMPONENT_INSURANCE_VALUE = 250;
8	const BUILDING_BLOCK_SIZE = 3;
9	const BUILDING_BLOCK_BASE_PREMIUM = 60;
10	const CURSE_SURCHARGE_RATE = 0.5;
11	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
12	const HIGH_ENCHANTMENT_THRESHOLD = 5;
13	const DEDUCTIBLE_PER_DAMAGE = 100;
14	const CAP_MULTIPLIER = 2;
15	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
16	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
17	
18	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
19	type Customer = { yearsWithMHPCO: number };
20	type Damage = { itemType: string; amount: number };
21	type Incident = { cause: string; damages: Damage[] };
22	type QuoteStep = { op: "quote"; items: Item[] };
23	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
24	type Step = QuoteStep | ClaimStep;
25	type Scenario = { customer: Customer; steps: Step[] };
26	
27	type QuoteResult = { premium: number };
28	type ClaimResult = { payout: number; remainingCap: number };
29	type StepResult = QuoteResult | ClaimResult;
30	
31	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	};
37	
38	const MAIN_ITEM_INSURANCE_VALUE: Record<string, number> = {
39	  sword: 1000,
40	  amulet: 600,
41	  staff: 800,
42	  potion: 400,
43	};
44	
45	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
46	
47	const isComponent = (type: string) => COMPONENT_TYPES.has(type);
48	
49	const itemInsuranceValue = (item: Item): number =>
50	  isComponent(item.type) ? COMPONENT_INSURANCE_VALUE : MAIN_ITEM_INSURANCE_VALUE[item.type];
51	
52	const componentsGroupBase = (count: number): number => {
53	  if (count === BUILDING_BLOCK_SIZE) return BUILDING_BLOCK_BASE_PREMIUM;
54	  return count * COMPONENT_BASE_PREMIUM;
55	};
56	
57	const itemBasePremium = (item: Item): number => {
58	  if (isComponent(item.type)) return COMPONENT_BASE_PREMIUM;
59	  return MAIN_ITEM_BASE_PREMIUM[item.type];
60	};
61	
62	const itemSurcharges = (item: Item): number => {
63	  if (isComponent(item.type)) return 0;
64	  const base = itemBasePremium(item);
65	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
66	  const highEnchantment =
67	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
68	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
69	      : 0;
70	  return curse + highEnchantment;
71	};
72	
73	const sum = (values: number[]): number => values.reduce((a, b) => a + b, 0);
74	
75	const countByType = (items: Item[]): Map<string, number> =>
76	  items.reduce((counts, item) => {
77	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
78	    return counts;
79	  }, new Map<string, number>());
80	
81	const policyBaseSum = (items: Item[]): number => {
82	  const mainItems = items.filter((i) => !isComponent(i.type));
83	  const components = items.filter((i) => isComponent(i.type));
84	  const mainSum = sum(mainItems.map(itemBasePremium));
85	  const componentsSum = sum(
86	    Array.from(countByType(components).values(), componentsGroupBase)
87	  );
88	  return mainSum + componentsSum;
89	};
90	
91	const policyItemSurcharges = (items: Item[]): number => sum(items.map(itemSurcharges));
92	
93	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
94	  const baseSum = policyBaseSum(items);
95	  const surcharges = policyItemSurcharges(items);
96	  const firstContractInsurance = baseSum * FIRST_CONTRACT_INSURANCE_RATE;
97	  const loyaltyDiscount =
98	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? baseSum * LOYALTY_DISCOUNT_RATE : 0;
99	  const followUpDiscount = isFollowUp ? baseSum * FOLLOW_UP_CONTRACT_DISCOUNT_RATE : 0;
100	  return Math.ceil(
101	    baseSum + surcharges + firstContractInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE
102	  );
103	};
104	
105	type Policy = { items: Item[]; cap: number };
106	
107	const createPolicy = (items: Item[]): Policy => {
108	  const insuranceSum = sum(items.map(itemInsuranceValue));
109	  return { items, cap: insuranceSum * CAP_MULTIPLIER };
110	};
111	
112	const damagePayout = (damage: Damage, items: Item[]): number => {
113	  const item = items.find((i) => i.type === damage.itemType);
114	  const reimbursable =
115	    item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
116	      ? damage.amount * HIGH_ENCHANTMENT_CLAIM_RATE
117	      : damage.amount;
118	  return Math.max(0, reimbursable - DEDUCTIBLE_PER_DAMAGE);
119	};
120	
121	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
122	  const rawPayout = sum(incident.damages.map((d) => damagePayout(d, policy.items)));
123	  const payout = Math.min(rawPayout, policy.cap);
124	  policy.cap -= payout;
125	  return { payout: Math.floor(payout), remainingCap: policy.cap };
126	};
127	
128	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
129	  const policies: Policy[] = [];
130	  let quoteCount = 0;
131	  const results: StepResult[] = scenario.steps.map((step) => {
132	    if (step.op === "quote") {
133	      const isFollowUp = quoteCount > 0;
134	      quoteCount++;
135	      policies.push(createPolicy(step.items));
136	      return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
137	    }
138	    return processClaim(policies[step.policy], step.incident);
139	  });
140	  return { results };
141	};
